// interconnect_inject.js — v2 (index.html "correct format")
// Fetches the locked template from the repo and substitutes section tokens.
// TOKENS: {{DATELINE}} {{VOL}} {{NO}} {{QUEUE_DATE}} {{LEDE}} {{CONNECTOR_ROWS}}
//         {{QUEUE_SPOTLIGHT}} {{LEAD_STORY}} {{CAMPUS_STORIES}} {{POLICY_FLAGS}} {{PRICING_CONTEXT}}
//
// UPSTREAM CONTRACT:
//   Set Metadata        -> { dateline, vol, no }
//   Generate Lede       -> { lede }
//   Generate Feature    -> { label, title, dek, paragraphs:[], data_label, data_items:[{num,lbl}] }
//   Generate Signals    -> [ { hed, dek, paragraphs:[] } ]                (Campus Announcements stories)
//   Generate Connectors -> [ { market_tag, load_name, load_note, mw, supply_count, supply_note, strategic_note } ]
//   Generate Flags      -> [ { entity, note } ]
//   Generate Pricing    -> { paragraphs:[] }
//   Fetch Queue Records -> Airtable rows (Project Name, Region, Generation Type, MW Capacity, Status, POI Name)

const TEMPLATE_URL = 'https://api.github.com/repos/nexphaseadvisory/Reports/contents/interconnect/template/the_interconnect_TEMPLATE.html?ref=main';
const resp = await this.helpers.httpRequest({
  method: 'GET', url: TEMPLATE_URL,
  headers: { 'Accept': 'application/vnd.github.raw', 'User-Agent': 'n8n-interconnect-publisher' },
  json: false
});
let TEMPLATE;
if (typeof resp === 'string') TEMPLATE = resp;
else if (resp && resp.content) TEMPLATE = Buffer.from(resp.content, 'base64').toString('utf8');
else TEMPLATE = String(resp);
if (TEMPLATE.indexOf('{{LEDE}}') === -1 || TEMPLATE.indexOf('{{LEAD_STORY}}') === -1) {
  throw new Error('Template fetch failed or missing v2 tokens — got ' + TEMPLATE.length + ' chars from ' + TEMPLATE_URL);
}

// ---------- helpers ----------
function claudeJSON(resp) {
  try {
    const content = (resp && resp.content) || [];
    const text = content.filter(b => b && b.type === 'text').map(b => b.text).join('').trim();
    return JSON.parse(text.replace(/```json|```/g, '').trim());
  } catch (e) { return null; }
}
function esc(s) {
  return String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}
function paras(arr, firstStyle) {
  const a = Array.isArray(arr) ? arr : (arr ? [arr] : []);
  return a.map((p, i) =>
    '<p class="body-text"' + (i > 0 ? ' style="margin-top:8px"' : (firstStyle || '')) + '>' + esc(p) + '</p>'
  ).join('\n      ');
}

// ---------- pull upstream ----------
const meta      = $('Set Metadata').first().json;
const lede      = (claudeJSON($('Generate Lede').first().json) || { lede: '' }).lede || '';
const feature   = claudeJSON($('Generate Feature').first().json) || {};
const stories   = claudeJSON($('Generate Signals').first().json) || [];
const connectors= claudeJSON($('Generate Connectors').first().json) || [];
const flags     = claudeJSON($('Generate Flags').first().json) || [];
const pricing   = claudeJSON($('Generate Pricing').first().json) || { paragraphs: [] };
const queueRaw  = $('Fetch Queue Records').all().map(i => i.json);

// ---------- CONNECTOR_ROWS ----------
const connectorRows = (Array.isArray(connectors) ? connectors : []).map(c =>
  '<tr>\n' +
  '          <td><span class="market-tag">' + esc(c.market_tag) + '</span></td>\n' +
  '          <td><span class="load-name">' + esc(c.load_name) + '</span>' +
       (c.load_note ? '<div class="queue-note">' + esc(c.load_note) + '</div>' : '') + '</td>\n' +
  '          <td><span class="mw-val">' + esc(c.mw) + '</span></td>\n' +
  '          <td><span class="supply-count">' + esc(c.supply_count) + '</span>' +
       (c.supply_note ? '<div class="queue-note">' + esc(c.supply_note) + '</div>' : '') + '</td>\n' +
  '          <td style="font-size:11px;color:#374151">' + esc(c.strategic_note) + '</td>\n' +
  '        </tr>'
).join('\n        ');

// ---------- QUEUE_SPOTLIGHT (top queue records by MW) ----------
const queueSpotlight = queueRaw.map(q => ({
  id: q['Project Name'] || q['POI Name'] || '',
  type: q['Generation Type'] || q['Project Type'] || '',
  mw: (q['MW Capacity'] != null ? q['MW Capacity'] : ''),
  region: q['Region'] || '',
  status: q['Status'] || '',
  poi: q['POI Name'] || ''
}))
  .sort((a, b) => (parseFloat(b.mw) || 0) - (parseFloat(a.mw) || 0))
  .slice(0, 4)
  .map(q => {
    const desc = [
      (q.mw !== '' ? q.mw + ' MW ' : '') + esc(q.type) + (q.region ? ' · ' + esc(q.region) : ''),
      [esc(q.status), esc(q.poi)].filter(Boolean).join(' · ')
    ].filter(Boolean).join('<br>');
    return '<div class="qs-item">\n' +
      '            <div class="qs-id">' + esc(q.id) + '</div>\n' +
      '            <div class="qs-desc">' + desc + '</div>\n' +
      '          </div>';
  }).join('\n          ');

// ---------- LEAD_STORY (feature analysis + data-box) ----------
const dataItems = (Array.isArray(feature.data_items) ? feature.data_items : []).map(di =>
  '<div class="data-item"><div class="num">' + esc(di.num) + '</div><div class="lbl">' + esc(di.lbl) + '</div></div>'
).join('\n          ');
const dataBox = (feature.data_label || dataItems) ?
  '\n      <div class="data-box">\n' +
  '        <div class="data-label">' + esc(feature.data_label) + '</div>\n' +
  '        <div class="data-grid">\n          ' + dataItems + '\n        </div>\n' +
  '      </div>' : '';
const leadStory =
  '<div class="sec">\n' +
  '      <div class="sec-label">' + esc(feature.label || 'Interconnection') + '</div>\n' +
  '      <h2>' + esc(feature.title || '') + '</h2>\n' +
  '    </div>\n\n' +
  '    <div class="lead-story">\n' +
  '      <p class="dek">' + esc(feature.dek || '') + '</p>\n' +
  '      ' + paras(feature.paragraphs) + dataBox + '\n' +
  '    </div>';

// ---------- CAMPUS_STORIES (2-col story grid) ----------
const campusStories = (Array.isArray(stories) ? stories : []).map(s =>
  '<div class="story">\n' +
  '        <div class="hed">' + esc(s.hed || s.headline) + '</div>\n' +
  '        <div class="dek">' + esc(s.dek || '') + '</div>\n' +
  '        ' + paras(s.paragraphs || s.detail) + '\n' +
  '      </div>'
).join('\n      ');

// ---------- POLICY_FLAGS ----------
const policyFlags = (Array.isArray(flags) ? flags : []).map(f =>
  '<div class="flag-item">\n' +
  '        <span class="flag-co">' + esc(f.entity) + '</span>\n' +
  '        <span class="flag-note">' + esc(f.note) + '</span>\n' +
  '      </div>'
).join('\n      ');

// ---------- PRICING_CONTEXT ----------
const pricingHtml = paras(pricing.paragraphs || pricing);

// ---------- QUEUE_DATE ----------
const months = ['January','February','March','April','May','June','July','August','September','October','November','December'];
const now = new Date();
const queueDate = months[now.getMonth()] + ' ' + now.getDate() + ', ' + now.getFullYear();

// ---------- inject ----------
const html = TEMPLATE
  .split('{{DATELINE}}').join(esc(meta.dateline))
  .split('{{VOL}}').join(esc(meta.vol))
  .split('{{NO}}').join(esc(meta.no))
  .split('{{QUEUE_DATE}}').join(esc(queueDate))
  .split('{{LEDE}}').join(esc(lede))
  .split('{{CONNECTOR_ROWS}}').join(connectorRows)
  .split('{{QUEUE_SPOTLIGHT}}').join(queueSpotlight)
  .split('{{LEAD_STORY}}').join(leadStory)
  .split('{{CAMPUS_STORIES}}').join(campusStories)
  .split('{{POLICY_FLAGS}}').join(policyFlags)
  .split('{{PRICING_CONTEXT}}').join(pricingHtml);

if (html.indexOf('{{') !== -1) {
  const leftover = (html.match(/\{\{[A-Z_]+\}\}/g) || []).join(', ');
  throw new Error('Unsubstituted tokens remain: ' + leftover);
}

return [{ json: { html, dateline: meta.dateline, vol: meta.vol, no: meta.no } }];

// Persist the generated draft in workflow static data, keyed by vol/no.
const sd = $getWorkflowStaticData('global');
const j = $input.first().json;
const rec = { html: j.html, filename: j.filename, vol: j.vol, no: j.no, dateline: j.dateline };
sd['draft_' + j.vol + '_' + j.no] = rec;  // keyed by vol/no
sd.latestDraft = rec;                      // pointer to most recent draft
return [{ json: j }];  // pass through for the draft email

// Publish path: read the stored draft from static data and hand it to GitHub — Publish.
const sd = $getWorkflowStaticData('global');
const j = ($input.first() && $input.first().json) || {};
const body = j.body || {};  // optional { vol, no } in the publish webhook POST body
let rec = (body.vol != null && body.no != null) ? sd['draft_' + body.vol + '_' + body.no] : sd.latestDraft;
if (!rec || !rec.html) { throw new Error('No stored draft found to publish. Fire the draft webhook first.'); }
return [{ json: rec }];

